CREATE TABLE event_sources (id uuid PRIMARY KEY, name varchar(255) NOT NULL UNIQUE, url varchar(2048) NOT NULL, active boolean NOT NULL, parser_key varchar(255) NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE TABLE events (id uuid PRIMARY KEY, title varchar(255) NOT NULL, organizer varchar(255), description text, event_type varchar(32) NOT NULL, start_at timestamptz NOT NULL, end_at timestamptz, location_name varchar(255), city varchar(255) NOT NULL, address varchar(255), attendance_mode varchar(32) NOT NULL, source_url varchar(2048) NOT NULL, source_name varchar(255) NOT NULL, external_event_id varchar(255), fingerprint varchar(64) NOT NULL, last_checked_at timestamptz NOT NULL, status varchar(32) NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL, CONSTRAINT uq_event_fingerprint UNIQUE(fingerprint));
CREATE TABLE event_tags (event_id uuid NOT NULL REFERENCES events(id) ON DELETE CASCADE, tag varchar(255));
CREATE INDEX idx_events_start ON events(start_at); CREATE INDEX idx_events_city ON events(lower(city)); CREATE INDEX idx_event_tags_tag ON event_tags(lower(tag));
CREATE TABLE event_changes (id uuid PRIMARY KEY, event_id uuid NOT NULL REFERENCES events(id), changed_field varchar(255) NOT NULL, old_value text, new_value text, detected_at timestamptz NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE TABLE app_users (id uuid PRIMARY KEY, display_name varchar(255), phone_number varchar(255) UNIQUE, whatsapp_opt_in boolean NOT NULL, preferred_city varchar(255), preferred_attendance_mode varchar(32), created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE TABLE user_preferred_event_types (user_id uuid NOT NULL REFERENCES app_users(id) ON DELETE CASCADE, event_type varchar(32));
CREATE TABLE user_interests (id uuid PRIMARY KEY, user_id uuid NOT NULL REFERENCES app_users(id), tag varchar(255) NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL, UNIQUE(user_id,tag));
CREATE TABLE user_searches (id uuid PRIMARY KEY, user_id uuid REFERENCES app_users(id), query varchar(255) NOT NULL, normalized_query varchar(255) NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE INDEX idx_user_search_normalized ON user_searches(normalized_query);
CREATE TABLE subscriptions (id uuid PRIMARY KEY, user_id uuid NOT NULL REFERENCES app_users(id), event_id uuid REFERENCES events(id), tag varchar(255), active boolean NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE TABLE notifications (id uuid PRIMARY KEY, user_id uuid NOT NULL REFERENCES app_users(id), event_id uuid REFERENCES events(id), type varchar(32) NOT NULL, title varchar(255) NOT NULL, body text NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE TABLE notification_deliveries (id uuid PRIMARY KEY, notification_id uuid NOT NULL REFERENCES notifications(id), channel varchar(32) NOT NULL, status varchar(32) NOT NULL, provider_reference varchar(255), error_message varchar(255), delivered_at timestamptz, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE TABLE chat_sessions (id uuid PRIMARY KEY, user_id uuid REFERENCES app_users(id), state varchar(255) NOT NULL, completed boolean NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE TABLE chat_messages (id uuid PRIMARY KEY, session_id uuid NOT NULL REFERENCES chat_sessions(id), role varchar(32) NOT NULL, content text NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE TABLE event_groups (id uuid PRIMARY KEY, event_id uuid NOT NULL UNIQUE REFERENCES events(id), name varchar(255) NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE TABLE event_group_members (id uuid PRIMARY KEY, group_id uuid NOT NULL REFERENCES event_groups(id), user_id uuid NOT NULL REFERENCES app_users(id), created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL, UNIQUE(group_id,user_id));
CREATE TABLE connection_requests (id uuid PRIMARY KEY, requester_id uuid NOT NULL REFERENCES app_users(id), recipient_id uuid NOT NULL REFERENCES app_users(id), status varchar(32) NOT NULL, created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
CREATE TABLE user_connections (id uuid PRIMARY KEY, user_a_id uuid NOT NULL REFERENCES app_users(id), user_b_id uuid NOT NULL REFERENCES app_users(id), created_at timestamptz NOT NULL, updated_at timestamptz NOT NULL);
